const event = $('Execute Workflow Trigger').item.json;
const pgRow = $('Fetch QA Data from PG').item.json || {};
const safeArr = v => Array.isArray(v) ? v : [];
const safeObj = v => (v && typeof v === 'object' && !Array.isArray(v)) ? v : {};

// GitHub data
const bugsBack = safeArr($('GitHub Bug Issues Backend').item.json);
const bugsFront = safeArr($('GitHub Bug Issues Frontend').item.json);
const prsBack = safeArr($('GitHub Closed PRs Backend').item.json);
const prsFront = safeArr($('GitHub Closed PRs Frontend').item.json);

const bugsBackCount = bugsBack.filter(i => !i.pull_request).length;
const bugsFrontCount = bugsFront.filter(i => !i.pull_request).length;
const totalBugsAbiertos = bugsBackCount + bugsFrontCount;

// PRs rechazados (cerrados sin merge) en últimos 30d
const cutoff30d = new Date(Date.now() - 30 * 86400000);
const prsRechazadosBack = prsBack.filter(pr => !pr.merged_at && new Date(pr.closed_at) > cutoff30d).length;
const prsRechazadosFront = prsFront.filter(pr => !pr.merged_at && new Date(pr.closed_at) > cutoff30d).length;
const totalPrsRechazados = prsRechazadosBack + prsRechazadosFront;

// PR avg review time (merged PRs)
const allMergedPrs = [...prsBack, ...prsFront].filter(pr => pr.merged_at);
const avgReviewHours = allMergedPrs.length > 0
  ? allMergedPrs.reduce((sum, pr) => {
      const created = new Date(pr.created_at);
      const merged = new Date(pr.merged_at);
      return sum + (merged - created) / 3600000;
    }, 0) / allMergedPrs.length
  : 0;

// Bugs críticos: los que tienen label 'critical' o 'high'
const bugsCriticosBack = bugsBack.filter(i => !i.pull_request && i.labels?.some(l => /critical|high|blocker/.test(l.name?.toLowerCase())));
const bugsCriticosFront = bugsFront.filter(i => !i.pull_request && i.labels?.some(l => /critical|high|blocker/.test(l.name?.toLowerCase())));
const totalBugsCriticos = bugsCriticosBack.length + bugsCriticosFront.length;

// Bug list detallado (top 5 más antiguos)
const allBugs = [
  ...bugsBack.filter(i => !i.pull_request).map(b => ({ ...b, repo: 'Backend' })),
  ...bugsFront.filter(i => !i.pull_request).map(b => ({ ...b, repo: 'Frontend' }))
].sort((a, b) => new Date(a.created_at) - new Date(b.created_at));
const topBugs = allBugs.slice(0, 6).map(b => {
  const diasAbierto = Math.floor((Date.now() - new Date(b.created_at)) / 86400000);
  const esCritico = b.labels?.some(l => /critical|high|blocker/.test(l.name?.toLowerCase()));
  return `${esCritico ? '🔴' : '🟡'} [${b.repo}] #${b.number} ${b.title?.slice(0, 60)} — ${diasAbierto}d abierto — asignado: ${b.assignee?.login || 'nadie'}`;
}).join('\n') || '(ninguno)';

// PG data
const kpis = safeObj(pgRow.kpis);
const github = safeObj(pgRow.github_data);
const totalDone = Number(pgRow.total_done_cards || 0);
const reopenCards = Number(pgRow.reopen_cards || 0);
const totalCards = Number(pgRow.total_cards || 1);
const workflowErrors14d = Number(pgRow.workflow_errors_14d || 0);
const highRisk30d = Number(pgRow.high_risk_decisions_30d || 0);
const progreso = Number(pgRow.progreso_pct || 0);
const pctConv = Number(kpis.pct_commits_convencionales || 0);
const busF = Number(kpis.bus_factor_14d || 0);
const prMergeRatio = Number(kpis.pr_merge_ratio_30d || 0);
const ciBack = safeObj(github.ci_back);
const ciFront = safeObj(github.ci_front);
const ciFailed14d = (ciBack.status === 'failure' ? 1 : 0) + (ciFront.status === 'failure' ? 1 : 0);

// Bug Reopen Rate
const bugReopenRate = totalDone > 0 ? Number(((reopenCards / totalDone) * 100).toFixed(2)) : 0;

// Deuda técnica score (0-100, mayor = peor)
let deudaScore = 0;
deudaScore += Math.min(totalBugsAbiertos * 5, 30);         // max 30 pts por bugs
deudaScore += Math.min(totalPrsRechazados * 4, 20);        // max 20 pts por PRs rechazados
deudaScore += Math.min(bugReopenRate * 0.5, 15);           // max 15 pts reopen rate
deudaScore += Math.min(totalBugsCriticos * 8, 20);         // max 20 pts bugs críticos
deudaScore += pctConv < 30 ? 10 : pctConv < 60 ? 5 : 0;  // conv commits
deudaScore += busF <= 1 ? 5 : 0;                           // bus factor
deudaScore = Math.min(Number(deudaScore.toFixed(2)), 100);

// Semáforo QA
let semaforo = 'verde';
if (deudaScore >= 50 || totalBugsCriticos >= 2 || bugReopenRate >= 20) semaforo = 'rojo';
else if (deudaScore >= 25 || totalBugsAbiertos >= 5 || totalPrsRechazados >= 3) semaforo = 'amarillo';

// Snapshot histórico comparativo
const historyQuery = `SELECT fecha, bugs_abiertos, deuda_tecnica_score, semaforo FROM qa_quality_snapshots ORDER BY id DESC LIMIT 3`;

const ciBackStr = ciBack.status ? `${ciBack.status} en ${ciBack.branch} (${(ciBack.date||'').slice(0,10)})` : 'sin datos';
const ciFrontStr = ciFront.status ? `${ciFront.status} en ${ciFront.branch} (${(ciFront.date||'').slice(0,10)})` : 'sin datos';

const prompt = `Eres el QA Quality Lead del proyecto PetSafe (NestJS backend + Angular frontend, cierre 10-jun-2026). Analiza los datos de calidad del sistema y genera un diagnóstico técnico accionable en español, texto plano, SIN markdown, SIN asteriscos.

DATA DE CALIDAD ACTUAL:
Bugs abiertos: ${totalBugsAbiertos} (Backend: ${bugsBackCount}, Frontend: ${bugsFrontCount})
Bugs críticos (alta prioridad): ${totalBugsCriticos}
PRs rechazados últimos 30d: ${totalPrsRechazados}
Bug Reopen Rate: ${bugReopenRate}% (${reopenCards} cards regresaron de Done)
Tiempo promedio de review de PRs merged: ${avgReviewHours.toFixed(1)}h
Errores de sistema/workflow 14d: ${workflowErrors14d}
Decisiones de alto riesgo 30d: ${highRisk30d}
CI Backend: ${ciBackStr}
CI Frontend: ${ciFrontStr}
Convención de commits: ${pctConv}%
Bus Factor 14d: ${busF} (autores distintos con commits)
Merge ratio PRs 30d: ${prMergeRatio}%
Progreso del proyecto: ${progreso}%
Score de Deuda Técnica: ${deudaScore}/100 (mayor = peor)
Semáforo QA: ${semaforo.toUpperCase()}

TOP BUGS MÁS ANTIGUOS:
${topBugs}

Estructura obligatoria (máx 3 oraciones por sección):
SALUD QA: Estado general (${semaforo}) con justificación numérica.
BUGS CRÍTICOS: Análisis de los bugs de mayor antigüedad o severidad. Menciona si alguno bloquea el cierre del proyecto.
DEUDA TÉCNICA: Qué generó la deuda (PRs rechazados, bugs sin cerrar, baja cobertura de convenciones).
RIESGOS DE CALIDAD: Top 2 riesgos específicos para la fecha de entrega.
ACCIONES: 3 acciones concretas asignadas por nombre del equipo (FG, DM, DP, JA) con criterio de done claro.`;

return [{ json: {
  correlation_id: event.correlation_id || `qa-${Date.now()}`,
  event_type: event.event_type || 'qa_review',
  actor: event.actor || 'system',
  prompt,
  // Métricas para persistir
  metrics: {
    bugs_abiertos: totalBugsAbiertos,
    bugs_criticos: totalBugsCriticos,
    prs_rechazados_30d: totalPrsRechazados,
    bug_reopen_rate_pct: bugReopenRate,
    pct_commits_convencionales: pctConv,
    ci_failures: ciFailed14d,
    semaforo,
    deuda_tecnica_score: deudaScore,
    avg_review_hours: Number(avgReviewHours.toFixed(1)),
    top_bugs: topBugs
  },
  semaforo,
  deudaScore,
  totalBugsAbiertos,
  totalBugsCriticos,
  topBugs
}}];

const raw = $json.text ?? $json.output ?? $json.response ?? '';
const iaText = typeof raw === 'string' ? raw.trim() : JSON.stringify(raw);
const ctx = $('Build QA Context').item.json;
const m = ctx.metrics || {};

const semE = { verde: '🟢', amarillo: '🟡', rojo: '🔴', gris: '⚪' }[ctx.semaforo] || '⚪';
const colorMap = { rojo: 15158332, amarillo: 16761095, verde: 3066993, gris: 9807270 };
const color = colorMap[ctx.semaforo] || 9807270;

const kpiField = [
  `🐛 Bugs abiertos: **${m.bugs_abiertos}** (${m.bugs_criticos} críticos)`,
  `🔄 Bug Reopen Rate: **${m.bug_reopen_rate_pct}%**`,
  `❌ PRs rechazados 30d: **${m.prs_rechazados_30d}**`,
  `⏱️ Avg review time: **${m.avg_review_hours}h**`,
  `📐 Commits convencionales: **${m.pct_commits_convencionales}%**`,
  `🏗️ Deuda técnica score: **${m.deuda_tecnica_score}/100**`
].join('\n');

const discord_payload = {
  username: 'PM PetSafe · QA Lead',
  embeds: [{
    title: `${semE} Reporte de Calidad PetSafe · ${new Date().toLocaleDateString('es-EC', { timeZone: 'America/Guayaquil' })}`,
    description: `Semáforo QA: **${ctx.semaforo.toUpperCase()}** · Score de deuda técnica: **${ctx.deudaScore}/100**`,
    color,
    fields: [
      { name: '📊 KPIs de Calidad', value: kpiField, inline: false },
      { name: '🐛 Top Bugs Más Antiguos', value: ctx.topBugs.slice(0, 900), inline: false },
      { name: '🤖 Diagnóstico QA', value: iaText.slice(0, 1000), inline: false }
    ],
    footer: { text: 'QA Quality Lead · PM PetSafe AI' },
    timestamp: new Date().toISOString()
  }],
  allowed_mentions: { parse: [] }
};

return [{ json: {
  correlation_id: ctx.correlation_id,
  agent_role: 'QA Quality Lead',
  decision_type: 'qa_review',
  input_summary: `QA: ${m.bugs_abiertos} bugs, deuda=${m.deuda_tecnica_score}, semaforo=${ctx.semaforo}`.slice(0,500),
  context_used: { semaforo: ctx.semaforo, deuda_score: ctx.deudaScore },
  evidence: { metrics: m, ia_diagnostico: iaText.slice(0,1000) },
  decision: { semaforo: ctx.semaforo, score: ctx.deudaScore },
  recommendation: iaText.slice(0,500),
  confidence: 0.9,
  risk_level: ctx.semaforo === 'rojo' ? 'high' : ctx.semaforo === 'amarillo' ? 'medium' : 'low',
  requires_human_approval: ctx.semaforo === 'rojo' || ctx.totalBugsCriticos >= 2,
  discord_payload,
  metrics: m,
  ia_text: iaText
}}];
